interface BarcodeGen493 { void create(); }
interface BarcodeReader493 { void build(); }
class BarcodeFactory493 {
    private final Supplier<BarcodeGen493> barcodeGenSupplier;
    private final Supplier<BarcodeReader493> barcodeReaderSupplier;
    public BarcodeFactory493(Supplier<BarcodeGen493> s1, Supplier<BarcodeReader493> s2) {
        this.barcodeGenSupplier = s1;
        this.barcodeReaderSupplier = s2;
    }
    public BarcodeGen493 createBarcodeGen() { return barcodeGenSupplier.get(); }
    public BarcodeReader493 createBarcodeReader() { return barcodeReaderSupplier.get(); }
    public static BarcodeFactory493 qr() {
        return new BarcodeFactory493(
            () -> () -> System.out.println("Qr BarcodeGen"),
            () -> () -> System.out.println("Qr BarcodeReader")
        );
    }
    public static BarcodeFactory493 code128() {
        return new BarcodeFactory493(
            () -> () -> System.out.println("Code128 BarcodeGen"),
            () -> () -> System.out.println("Code128 BarcodeReader")
        );
    }
}

